import io
import os
import torch
import torch.nn.functional as F
import torchvision.transforms as transforms
from PIL import Image
from flask import Flask, request, jsonify

# Configuration
MODEL_PATH = 'model.pth'  # Path to your trained PyTorch model
LABELS_PATH = 'labels.txt' # Path to a file containing class labels, one per line
HOST = '0.0.0.0'
PORT = 5000

# Initialize Flask app
app = Flask(__name__)

# Load model and labels globally to avoid reloading on each request
model = None
device = None
class_labels = []
image_transform = None

def load_model_and_labels():
    global model, device, class_labels, image_transform

    # Determine device
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    print(f"Using device: {device}")

    # Load the model
    if not os.path.exists(MODEL_PATH):
        raise FileNotFoundError(f"Model file not found at {MODEL_PATH}")
    
    # It's crucial that the model architecture is defined or imported here
    # For demonstration, let's assume a simple pre-trained ResNet18 structure
    # You should replace this with your actual model definition
    # Example:
    # from your_model_module import YourModelClass
    # model = YourModelClass(num_classes=len(class_labels))
    
    # If loading a state_dict for a pre-trained model like ResNet18
    # Make sure to initialize the model with the correct number of output classes
    # before loading the state_dict if it was trained with a different number.
    # For simplicity, let's assume the saved model is a complete model object.
    
    # If your model was saved as `torch.save(model.state_dict(), 'model.pth')`
    # you need to instantiate the model architecture first:
    # import torchvision.models as models
    # model = models.resnet18(pretrained=False)
    # num_ftrs = model.fc.in_features
    # num_classes_from_labels = len(class_labels) # This will be determined after loading labels
    # model.fc = torch.nn.Linear(num_ftrs, num_classes_from_labels)
    # model.load_state_dict(torch.load(MODEL_PATH, map_location=device))

    # If your model was saved as `torch.save(model, 'model.pth')`
    model = torch.load(MODEL_PATH, map_location=device)
    model.eval() # Set model to evaluation mode
    model.to(device)

    # Load class labels
    if not os.path.exists(LABELS_PATH):
        raise FileNotFoundError(f"Labels file not found at {LABELS_PATH}")
    with open(LABELS_PATH, 'r') as f:
        class_labels = [line.strip() for line in f if line.strip()]
    
    if not class_labels:
        raise ValueError(f"No labels found in {LABELS_PATH}")

    # Define image transformations
    # These transformations should match what your model was trained with
    # Example for common CNNs like ResNet, VGG, etc.
    image_transform = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224), # Or the input size your model expects
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])

    print(f"Model '{MODEL_PATH}' and labels '{LABELS_PATH}' loaded successfully.")
    print(f"Number of classes: {len(class_labels)}")


@app.route('/predict', methods=['POST'])
def predict():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part in the request'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if file:
        try:
            # Read the image file directly from the request
            image_bytes = file.read()
            image = Image.open(io.BytesIO(image_bytes)).convert('RGB')

            # Apply transformations
            input_tensor = image_transform(image)
            input_batch = input_tensor.unsqueeze(0) # Create a mini-batch as expected by the model

            # Move the input to the same device as the model
            input_batch = input_batch.to(device)

            with torch.no_grad(): # Disable gradient calculation for inference
                output = model(input_batch)

            # Apply softmax to get probabilities
            probabilities = F.softmax(output, dim=1)[0]
            
            # Get the predicted class index and confidence
            confidence, predicted_idx = torch.max(probabilities, 0)

            predicted_class = class_labels[predicted_idx.item()]
            confidence_score = confidence.item()

            return jsonify({
                'predicted_class': predicted_class,
                'confidence': confidence_score
            })

        except Exception as e:
            return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    # Load model and labels once when the server starts
    try:
        load_model_and_labels()
    except (FileNotFoundError, ValueError) as e:
        print(f"Error loading model or labels: {e}")
        print("Please ensure 'model.pth' and 'labels.txt' are in the same directory as the script, or provide correct paths.")
        exit(1) # Exit if essential files are missing

    # Run the Flask app
    app.run(host=HOST, port=PORT)